import { STORAGE_CONFIG } from "./config";
import { CloudflareR2Provider } from "./cloudflare-r2.provider";
import type { StorageProvider } from "./provider";
import type { UploadParams, SignedUrlOptions } from "./types";

/* ============================================
   StorageService
   The ONLY storage entry point for the application.
   Depends on StorageProvider interface — never on
   a concrete provider. Consumers (services, actions,
   API routes) import from here exclusively.
   ============================================ */

/**
 * Instantiate the active provider based on configuration.
 * To swap providers, change STORAGE_CONFIG.PROVIDER
 * and add the provider class — no other code changes needed.
 */
function createProvider(): StorageProvider {
  switch (STORAGE_CONFIG.PROVIDER) {
    case "cloudflare-r2":
      return new CloudflareR2Provider();
    // Future providers:
    // case "aws-s3": return new AwsS3Provider();
    // case "supabase": return new SupabaseStorageProvider();
    // case "local": return new LocalStorageProvider();
    default:
      return new CloudflareR2Provider();
  }
}

/** Singleton provider instance. */
const provider: StorageProvider = createProvider();

/**
 * StorageService — delegates all operations to the
 * injected StorageProvider. This is the single
 * storage facade for the entire application.
 */
export const storageService: StorageProvider = {
  get name() {
    return provider.name;
  },

  get bucket() {
    return provider.bucket;
  },

  upload(params: UploadParams): Promise<string> {
    return provider.upload(params);
  },

  replace(oldKey: string, params: UploadParams): Promise<string> {
    return provider.replace(oldKey, params);
  },

  delete(key: string): Promise<void> {
    return provider.delete(key);
  },

  exists(key: string): Promise<boolean> {
    return provider.exists(key);
  },

  getSignedUrl(key: string, options?: SignedUrlOptions): Promise<string> {
    return provider.getSignedUrl(key, options);
  },

  getDownloadUrl(key: string, options?: SignedUrlOptions): Promise<string> {
    return provider.getDownloadUrl(key, options);
  },

  getStreamingUrl(key: string, options?: SignedUrlOptions): Promise<string> {
    return provider.getStreamingUrl(key, options);
  },

  generateUploadUrl(
    key: string,
    contentType: string,
    options?: SignedUrlOptions
  ): Promise<string> {
    return provider.generateUploadUrl(key, contentType, options);
  },
};

/** Re-export types for consumer convenience. */
export type { StorageProvider, UploadParams, SignedUrlOptions };

import type { UploadParams, SignedUrlOptions } from "./types";

/* ============================================
   StorageProvider Interface
   Provider-agnostic contract for file storage.
   Every provider (R2, S3, Supabase, Local, etc.)
   must implement this interface.
   No provider-specific types leak here.
   ============================================ */

export interface StorageProvider {
  /** Human-readable provider name. */
  readonly name: string;

  /** The bucket/container name. */
  readonly bucket: string;

  /**
   * Upload a file to storage.
   * @returns the object key on success.
   */
  upload(params: UploadParams): Promise<string>;

  /**
   * Replace a file — deletes the old key, uploads the new one.
   * @returns the new object key.
   */
  replace(oldKey: string, params: UploadParams): Promise<string>;

  /**
   * Delete a single object from storage.
   */
  delete(key: string): Promise<void>;

  /**
   * Check if an object exists in storage.
   */
  exists(key: string): Promise<boolean>;

  /**
   * Generate a signed URL for downloading a private object.
   */
  getSignedUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a signed download URL.
   * Uses download-specific expiration by default.
   */
  getDownloadUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a signed streaming URL.
   * Uses streaming-specific expiration by default.
   */
  getStreamingUrl(key: string, options?: SignedUrlOptions): Promise<string>;

  /**
   * Generate a presigned URL for direct browser upload.
   * @returns a temporary upload URL.
   */
  generateUploadUrl(
    key: string,
    contentType: string,
    options?: SignedUrlOptions
  ): Promise<string>;
}

import {
  S3Client,
  PutObjectCommand,
  GetObjectCommand,
  DeleteObjectCommand,
  HeadObjectCommand,
  type PutObjectCommandInput,
} from "@aws-sdk/client-s3";
import { getSignedUrl } from "@aws-sdk/s3-request-presigner";

import { STORAGE_CONFIG } from "./config";
import type { StorageProvider } from "./provider";
import type { UploadParams, SignedUrlOptions } from "./types";

/* ============================================
   Cloudflare R2 Storage Provider
   Implements StorageProvider using the AWS SDK
   (R2 is S3-compatible). All Cloudflare-specific
   logic lives here and nowhere else.
   ============================================ */

/** Lazy-initialized S3 client (only created when first used). */
let _r2Client: S3Client | null = null;

function getR2Client(): S3Client {
  if (_r2Client) return _r2Client;

  _r2Client = new S3Client({
    region: "auto",
    endpoint: STORAGE_CONFIG.ENDPOINT,
    credentials: {
      accessKeyId: STORAGE_CONFIG.CREDENTIALS.accessKey,
      secretAccessKey: STORAGE_CONFIG.CREDENTIALS.secretKey,
    },
  });
  return _r2Client;
}

export class CloudflareR2Provider implements StorageProvider {
  readonly name = "cloudflare-r2";
  readonly bucket: string;

  constructor() {
    this.bucket = STORAGE_CONFIG.BUCKET;
  }

  async upload(params: UploadParams): Promise<string> {
    const { key, body, contentType, metadata } = params;

    const commandInput: PutObjectCommandInput = {
      Bucket: this.bucket,
      Key: key,
      Body: body,
      ContentType: contentType,
      Metadata: metadata,
    };

    await getR2Client().send(new PutObjectCommand(commandInput));
    return key;
  }

  async replace(oldKey: string, params: UploadParams): Promise<string> {
    await this.delete(oldKey);
    return this.upload(params);
  }

  async delete(key: string): Promise<void> {
    await getR2Client().send(
      new DeleteObjectCommand({
        Bucket: this.bucket,
        Key: key,
      })
    );
  }

  async exists(key: string): Promise<boolean> {
    try {
      await getR2Client().send(
        new HeadObjectCommand({
          Bucket: this.bucket,
          Key: key,
        })
      );
      return true;
    } catch {
      return false;
    }
  }

  async getSignedUrl(
    key: string,
    options?: SignedUrlOptions
  ): Promise<string> {
    const expiresIn = options?.expiresIn ?? STORAGE_CONFIG.SIGNED_URL_EXPIRATION.DOWNLOAD;

    const command = new GetObjectCommand({
      Bucket: this.bucket,
      Key: key,
    });

    return getSignedUrl(getR2Client(), command, { expiresIn });
  }

  async getDownloadUrl(
    key: string,
    options?: SignedUrlOptions
  ): Promise<string> {
    return this.getSignedUrl(key, {
      expiresIn: options?.expiresIn ?? STORAGE_CONFIG.SIGNED_URL_EXPIRATION.DOWNLOAD,
    });
  }

  async getStreamingUrl(
    key: string,
    options?: SignedUrlOptions
  ): Promise<string> {
    return this.getSignedUrl(key, {
      expiresIn: options?.expiresIn ?? STORAGE_CONFIG.SIGNED_URL_EXPIRATION.STREAMING,
    });
  }

  async generateUploadUrl(
    key: string,
    contentType: string,
    options?: SignedUrlOptions
  ): Promise<string> {
    const expiresIn = options?.expiresIn ?? STORAGE_CONFIG.SIGNED_URL_EXPIRATION.UPLOAD;

    const command = new PutObjectCommand({
      Bucket: this.bucket,
      Key: key,
      ContentType: contentType,
    });

    return getSignedUrl(getR2Client(), command, { expiresIn });
  }
}

