import { z } from "zod";

/* ============================================
   Environment Variable Validation
   Fail immediately if any required variable
   is missing on the server.
   ============================================ */

const envSchema = z.object({
  /* ── Database ───────────────────────────── */
  DATABASE_URL: z.string().min(1, "DATABASE_URL is required"),
  DIRECT_URL: z.string().min(1, "DIRECT_URL is required"),

  /* ── Supabase ───────────────────────────── */
  NEXT_PUBLIC_SUPABASE_URL: z
    .string()
    .url("NEXT_PUBLIC_SUPABASE_URL must be a valid URL")
    .min(1, "NEXT_PUBLIC_SUPABASE_URL is required"),
  NEXT_PUBLIC_SUPABASE_ANON_KEY: z
    .string()
    .min(1, "NEXT_PUBLIC_SUPABASE_ANON_KEY is required"),
  SUPABASE_SERVICE_ROLE_KEY: z
    .string()
    .min(1, "SUPABASE_SERVICE_ROLE_KEY is required"),

  /* ── Cloudflare R2 ──────────────────────── */
  R2_ENDPOINT: z
    .string()
    .url("R2_ENDPOINT must be a valid URL")
    .min(1, "R2_ENDPOINT is required"),
  R2_ACCESS_KEY: z.string().min(1, "R2_ACCESS_KEY is required"),
  R2_SECRET_KEY: z.string().min(1, "R2_SECRET_KEY is required"),
  R2_BUCKET: z.string().min(1, "R2_BUCKET is required"),
  R2_PUBLIC_URL: z
    .string()
    .url("R2_PUBLIC_URL must be a valid URL")
    .min(1, "R2_PUBLIC_URL is required"),

  /* ── App (public) ───────────────────────── */
  NEXT_PUBLIC_APP_NAME: z.string().default("Photography Pixel Hub"),
  NEXT_PUBLIC_APP_URL: z
    .string()
    .url("NEXT_PUBLIC_APP_URL must be a valid URL")
    .default("http://localhost:3000"),

  /* ── Auth ──────────────────────────────── */
  AUTH_SECRET: z.string().min(1, "AUTH_SECRET is required"),

  /* ── Node Env ──────────────────────────── */
  NODE_ENV: z
    .enum(["development", "production", "test"])
    .default("development"),
});

export type Env = z.infer<typeof envSchema>;

/**
 * Parse and validate environment variables.
 * Throws immediately if any required variable is missing or invalid.
 *
 * This function is server-only — never import from client components.
 */
function loadEnv(): Env {
  const parsed = envSchema.safeParse(process.env);

  if (!parsed.success) {
    const errors = parsed.error.issues
      .map((issue) => `  ✗ ${issue.path.join(".")}: ${issue.message}`)
      .join("\n");

    throw new Error(
      `\n❌ Invalid environment variables:\n${errors}\n\n` +
        `Please check your .env file and ensure all required variables are set.\n`
    );
  }

  return parsed.data;
}

export const env = loadEnv();

import { NextRequest, NextResponse } from "next/server";

import { getCurrentUser } from "@/lib/auth/session";
import { storageService } from "@/lib/storage/storage.service";
import { generateStorageKey, getMimeType, getExtension, validateVideoFile } from "@/lib/video/metadata";

export const maxDuration = 60;

/* ============================================
   Upload API Route
   Handles multipart video uploads via StorageService.
   Provider-agnostic — no direct Cloudflare imports.
   ============================================ */

export async function POST(request: NextRequest) {
  const user = await getCurrentUser();
  if (!user) {
    return NextResponse.json(
      { error: "يجب تسجيل الدخول" },
      { status: 401 }
    );
  }

  try {
    const formData = await request.formData();
    const file = formData.get("file") as File | null;
    const projectId = formData.get("projectId") as string | null;

    if (!file) {
      return NextResponse.json(
        { error: "الملف مطلوب" },
        { status: 400 }
      );
    }

    if (!projectId) {
      return NextResponse.json(
        { error: "المشروع مطلوب" },
        { status: 400 }
      );
    }

    // Validate file type and size
    const validation = validateVideoFile(file);
    if (!validation.valid) {
      return NextResponse.json(
        { error: validation.error },
        { status: 400 }
      );
    }

    // Generate storage key
    const storageKey = generateStorageKey(projectId, file.name);
    const mimeType = getMimeType(file);
    const extension = getExtension(file.name);

    // Read file as buffer
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // Upload via StorageService
    await storageService.upload({
      key: storageKey,
      body: buffer,
      contentType: mimeType,
      metadata: {
        "original-filename": file.name,
        "project-id": projectId,
      },
    });

    return NextResponse.json({
      success: true,
      storageKey,
      storageBucket: storageService.bucket,
      mimeType,
      extension,
      fileSize: file.size,
    });
  } catch (error) {
    console.error("Upload error:", error);
    return NextResponse.json(
      { error: "فشل في رفع الملف" },
      { status: 500 }
    );
  }
}

"use client";

import { useState, useCallback, useRef } from "react";

import type { UploadQueueItem } from "@/types/video";
import { extractVideoMetadata } from "@/lib/video/metadata";
import { completeUploadAction } from "@/actions/uploads/complete-upload";

/* ============================================
   useUploadQueue — Client-side upload manager
   Handles file queue, upload to R2, progress,
   cancel, retry, and completion.
   ============================================ */

export function useUploadQueue(projectId: string | null) {
  const [items, setItems] = useState<UploadQueueItem[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const abortControllers = useRef<Map<string, AbortController>>(new Map());

  const addFiles = useCallback((files: FileList | File[]) => {
    const list = Array.from(files);
    const newItems: UploadQueueItem[] = list.map((file) => ({
      id: crypto.randomUUID(),
      file,
      status: "waiting" as const,
      progress: 0,
    }));
    setItems((prev) => [...prev, ...newItems]);
  }, []);

  const removeItem = useCallback((id: string) => {
    const controller = abortControllers.current.get(id);
    if (controller) {
      controller.abort();
      abortControllers.current.delete(id);
    }
    setItems((prev) => prev.filter((f) => f.id !== id));
  }, []);

  const updateItem = useCallback(
    (id: string, updates: Partial<UploadQueueItem>) => {
      setItems((prev) =>
        prev.map((f) => (f.id === id ? { ...f, ...updates } : f))
      );
    },
    []
  );

  const clearCompleted = useCallback(() => {
    setItems((prev) => prev.filter((f) => f.status !== "completed"));
  }, []);

  const clearAll = useCallback(() => {
    abortControllers.current.forEach((c) => c.abort());
    abortControllers.current.clear();
    setItems([]);
  }, []);

  const uploadFile = useCallback(
    async (item: UploadQueueItem) => {
      if (!projectId) return;

      const abortController = new AbortController();
      abortControllers.current.set(item.id, abortController);

      updateItem(item.id, { status: "uploading", progress: 0, error: undefined });

      try {
        // Extract metadata client-side
        let duration: number | undefined;
        let width: number | undefined;
        let height: number | undefined;
        try {
          const meta = await extractVideoMetadata(item.file);
          duration = meta.duration || undefined;
          width = meta.width || undefined;
          height = meta.height || undefined;
        } catch {
          // Metadata extraction failed — continue without it
        }

        // Upload via FormData to /api/upload
        const formData = new FormData();
        formData.append("file", item.file);
        formData.append("projectId", projectId);

        updateItem(item.id, { status: "uploading", progress: 10 });

        const response = await fetch("/api/upload", {
          method: "POST",
          body: formData,
          signal: abortController.signal,
        });

        if (!response.ok) {
          const data = await response.json().catch(() => ({}));
          throw new Error(data.error ?? "فشل في رفع الملف");
        }

        updateItem(item.id, { status: "processing", progress: 90 });

        const result = await response.json();

        // Complete upload — create video record
        const completeResult = await completeUploadAction({
          projectId,
          title: item.file.name.replace(/\.[^.]+$/, ""),
          originalFileName: item.file.name,
          storageKey: result.storageKey,
          storageBucket: result.storageBucket,
          mimeType: result.mimeType,
          extension: result.extension,
          fileSize: result.fileSize,
          duration,
          width,
          height,
        });

        if (completeResult.success) {
          updateItem(item.id, {
            status: "completed",
            progress: 100,
            videoId: completeResult.videoId,
          });
        } else {
          throw new Error(completeResult.error ?? "فشل في إكمال الرفع");
        }
      } catch (error) {
        if ((error as Error).name === "AbortError") {
          updateItem(item.id, { status: "failed", error: "تم الإلغاء" });
        } else {
          updateItem(item.id, {
            status: "failed",
            error: (error as Error).message ?? "فشل في الرفع",
          });
        }
      } finally {
        abortControllers.current.delete(item.id);
      }
    },
    [projectId, updateItem]
  );

  const startUpload = useCallback(async () => {
    if (!projectId || isUploading) return;
    setIsUploading(true);

    const pending = items.filter((f) => f.status === "waiting" || f.status === "failed");
    for (const item of pending) {
      await uploadFile(item);
    }

    setIsUploading(false);
  }, [projectId, isUploading, items, uploadFile]);

  const retryItem = useCallback(
    async (id: string) => {
      const item = items.find((f) => f.id === id);
      if (!item) return;
      updateItem(id, { status: "waiting", progress: 0, error: undefined });
      await uploadFile({ ...item, status: "waiting", progress: 0, error: undefined });
    },
    [items, updateItem, uploadFile]
  );

  const cancelUpload = useCallback((id: string) => {
    const controller = abortControllers.current.get(id);
    if (controller) {
      controller.abort();
      abortControllers.current.delete(id);
    }
    updateItem(id, { status: "failed", error: "تم الإلغاء" });
  }, [updateItem]);

  return {
    items,
    isUploading,
    addFiles,
    removeItem,
    retryItem,
    cancelUpload,
    startUpload,
    clearCompleted,
    clearAll,
  };
}

import { prisma } from "@/lib/prisma";
import type { Prisma, VideoStatus } from "@prisma/client";

/* ============================================
   Video Repository
   The ONLY layer that interacts with Prisma
   for Video operations.
   ============================================ */

export type VideoWithRelations = Prisma.VideoGetPayload<{
  include: { project: true; downloads: true; views: true };
}>;

export type VideoCreateInput = Prisma.VideoUncheckedCreateInput;
export type VideoUpdateInput = Prisma.VideoUncheckedUpdateInput;
export type VideoWhereInput = Prisma.VideoWhereInput;
export type VideoWhereUniqueInput = Prisma.VideoWhereUniqueInput;

/** Map filter values to Prisma status conditions. */
function statusFromFilter(
  filter: string
): Prisma.VideoWhereInput["status"] | undefined {
  const map: Record<string, string> = {
    ready: "READY",
    processing: "PROCESSING",
    uploading: "UPLOADING",
    failed: "FAILED",
    deleted: "DELETED",
  };
  return map[filter] as Prisma.VideoWhereInput["status"] | undefined;
}

/** Build the WHERE clause for search + filter. */
function buildWhere(params: {
  projectId?: string;
  search?: string;
  filter?: string;
}): VideoWhereInput {
  const where: VideoWhereInput = {};

  // Soft-delete: deleted videos excluded from default queries
  if (params.filter === "deleted") {
    where.status = "DELETED";
  } else if (params.filter && params.filter !== "all") {
    where.status = statusFromFilter(params.filter);
  } else {
    where.status = { not: "DELETED" };
  }

  if (params.projectId) {
    where.projectId = params.projectId;
  }

  if (params.search) {
    where.OR = [
      { videoCode: { contains: params.search, mode: "insensitive" } },
      { title: { contains: params.search, mode: "insensitive" } },
    ];
  }

  return where;
}

/** Build the ORDER BY clause for sorting. */
function buildOrderBy(sort: string): Prisma.VideoOrderByWithRelationInput {
  if (sort === "oldest") return { createdAt: "asc" };
  if (sort === "duration") return { duration: "desc" };
  if (sort === "size") return { fileSize: "desc" };
  return { createdAt: "desc" };
}

export const videoRepository = {
  findById(id: string) {
    return prisma.video.findUnique({
      where: { id },
      include: { project: true, downloads: true, views: true },
    });
  },

  findByVideoCode(videoCode: string) {
    return prisma.video.findUnique({
      where: { videoCode },
      include: { project: true },
    });
  },

  findByStorageKey(storageKey: string) {
    return prisma.video.findUnique({
      where: { storageKey },
      include: { project: true },
    });
  },

  create(data: VideoCreateInput) {
    return prisma.video.create({
      data,
      include: { project: true },
    });
  },

  update(id: string, data: VideoUpdateInput) {
    return prisma.video.update({
      where: { id },
      data,
      include: { project: true },
    });
  },

  /** Soft delete — set status to DELETED and deletedAt. */
  softDelete(id: string) {
    return prisma.video.update({
      where: { id },
      data: {
        status: "DELETED",
        deletedAt: new Date(),
      },
      include: { project: true },
    });
  },

  /** Restore a deleted video. */
  restore(id: string, status: string = "READY") {
    return prisma.video.update({
      where: { id },
      data: {
        status: status as VideoStatus,
        deletedAt: null,
      },
      include: { project: true },
    });
  },

  /** Hard delete — used only in tests/cleanup, never in production. */
  delete(id: string) {
    return prisma.video.delete({ where: { id } });
  },

  /** Paginated list with search, filter, and sort. */
  async findMany(params: {
    projectId?: string;
    skip?: number;
    take?: number;
    search?: string;
    filter?: string;
    sort?: string;
  }) {
    const where = buildWhere(params);
    const orderBy = buildOrderBy(params.sort ?? "newest");

    const [items, total] = await Promise.all([
      prisma.video.findMany({
        where,
        skip: params.skip,
        take: params.take,
        orderBy,
        include: {
          project: {
            select: { id: true, name: true, projectCode: true },
          },
        },
      }),
      prisma.video.count({ where }),
    ]);

    return { items, total };
  },

  count(where?: VideoWhereInput) {
    return prisma.video.count({ where });
  },

  /** Find the latest video code for sequential generation. */
  findLatestVideoCode() {
    return prisma.video.findFirst({
      orderBy: { videoCode: "desc" },
      select: { videoCode: true },
    });
  },

  /** Get statistics for a video. */
  async getStatistics(videoId: string) {
    const [views, downloads] = await Promise.all([
      prisma.view.count({ where: { videoId } }),
      prisma.download.count({ where: { videoId } }),
    ]);

    return { views, downloads };
  },

  /** Export all non-deleted videos as flat rows for CSV. */
  async findAllForExport(projectId?: string) {
    return prisma.video.findMany({
      where: {
        ...(projectId ? { projectId } : {}),
        status: { not: "DELETED" },
      },
      orderBy: { createdAt: "desc" },
      include: {
        project: {
          select: { name: true, projectCode: true },
        },
      },
    });
  },
};

import { prisma } from "@/lib/prisma";
import { videoRepository } from "@/repositories/video.repository";
import { activityService } from "@/services/activity.service";
import { storageService } from "@/lib/storage/storage.service";
import type { VideoStatus } from "@prisma/client";

/* ============================================
   Video Service
   Business logic layer — calls repositories only.
   ============================================ */

/** Format a sequential video code: VD-000001, VD-000002, etc. */
function formatVideoCode(sequence: number): string {
  return `VD-${String(sequence).padStart(6, "0")}`;
}

/** Generate the next unique video code using a transaction. */
async function generateUniqueVideoCode(): Promise<string> {
  return prisma.$transaction(async (tx) => {
    const latest = await tx.video.findFirst({
      orderBy: { videoCode: "desc" },
      select: { videoCode: true },
    });

    let sequence = 1;
    if (latest?.videoCode) {
      const match = latest.videoCode.match(/^VD-(\d+)$/);
      if (match) {
        sequence = parseInt(match[1]!, 10) + 1;
      }
    }

    return formatVideoCode(sequence);
  });
}

export const videoService = {
  async getById(id: string) {
    return videoRepository.findById(id);
  },

  async getByVideoCode(videoCode: string) {
    return videoRepository.findByVideoCode(videoCode);
  },

  async getByStorageKey(storageKey: string) {
    return videoRepository.findByStorageKey(storageKey);
  },

  async create(
    data: {
      projectId: string;
      title: string;
      originalFileName: string;
      storageKey: string;
      storageBucket: string;
      mimeType: string;
      extension: string;
      fileSize: bigint;
      duration?: number;
      width?: number;
      height?: number;
      status?: VideoStatus;
    },
    options?: { actorId?: string }
  ) {
    const videoCode = await generateUniqueVideoCode();

    const video = await videoRepository.create({
      videoCode,
      projectId: data.projectId,
      title: data.title.trim(),
      originalFileName: data.originalFileName,
      storageKey: data.storageKey,
      storageBucket: data.storageBucket,
      mimeType: data.mimeType,
      extension: data.extension,
      fileSize: data.fileSize,
      duration: data.duration,
      width: data.width,
      height: data.height,
      status: data.status ?? ("UPLOADING" as VideoStatus),
      uploadedAt: new Date(),
    });

    // Activity log: Video Uploaded
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "UPLOAD",
        entity: "video",
        entityId: video.id,
        metadata: {
          videoCode: video.videoCode,
          title: video.title,
          projectId: video.projectId,
        },
      });
    }

    return video;
  },

  async update(
    id: string,
    data: {
      title?: string;
      status?: VideoStatus;
      duration?: number;
      width?: number;
      height?: number;
      thumbnailUrl?: string;
      streamUrl?: string;
      downloadUrl?: string;
    },
    options?: { actorId?: string }
  ) {
    const updateData: Record<string, unknown> = {};
    if (data.title !== undefined) updateData.title = data.title.trim();
    if (data.status !== undefined) updateData.status = data.status;
    if (data.duration !== undefined) updateData.duration = data.duration;
    if (data.width !== undefined) updateData.width = data.width;
    if (data.height !== undefined) updateData.height = data.height;
    if (data.thumbnailUrl !== undefined) updateData.thumbnailUrl = data.thumbnailUrl || null;
    if (data.streamUrl !== undefined) updateData.streamUrl = data.streamUrl || null;
    if (data.downloadUrl !== undefined) updateData.downloadUrl = data.downloadUrl || null;

    if (data.status === "READY") {
      updateData.processedAt = new Date();
    }

    const video = await videoRepository.update(id, updateData as never);

    // Activity log: Video Processed
    if (options?.actorId && data.status === "READY") {
      await activityService.log({
        userId: options.actorId,
        type: "UPDATE",
        entity: "video",
        entityId: video.id,
        metadata: {
          videoCode: video.videoCode,
          title: video.title,
          status: data.status,
        },
      });
    }

    return video;
  },

  /** Mark video as processing. */
  async markProcessing(id: string) {
    return videoRepository.update(id, {
      status: "PROCESSING" as VideoStatus,
    } as never);
  },

  /** Mark video as ready with metadata. */
  async markReady(
    id: string,
    data: {
      duration?: number;
      width?: number;
      height?: number;
      thumbnailUrl?: string;
    },
    options?: { actorId?: string }
  ) {
    return this.update(
      id,
      {
        status: "READY" as VideoStatus,
        duration: data.duration,
        width: data.width,
        height: data.height,
        thumbnailUrl: data.thumbnailUrl,
      },
      options
    );
  },

  /** Mark video as failed. */
  async markFailed(id: string) {
    return videoRepository.update(id, {
      status: "FAILED" as VideoStatus,
    } as never);
  },

  /** Soft delete — archives the video. */
  async softDelete(id: string, options?: { actorId?: string }) {
    const video = await videoRepository.softDelete(id);

    // Activity log: Video Deleted
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "DELETE",
        entity: "video",
        entityId: id,
        metadata: {
          videoCode: video.videoCode,
          title: video.title,
        },
      });
    }

    return video;
  },

  /** Restore a deleted video. */
  async restore(id: string, options?: { actorId?: string }) {
    const video = await videoRepository.restore(id);

    // Activity log: Video Restored
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "RESTORE",
        entity: "video",
        entityId: id,
        metadata: {
          videoCode: video.videoCode,
          title: video.title,
        },
      });
    }

    return video;
  },

  /** Soft delete alias for backward compatibility. */
  async delete(id: string, options?: { actorId?: string }) {
    return this.softDelete(id, options);
  },

  async list(params: {
    projectId?: string;
    skip?: number;
    take?: number;
    search?: string;
    filter?: string;
    sort?: string;
  }) {
    return videoRepository.findMany(params);
  },

  async count(params: { projectId?: string; filter?: string }) {
    if (params.filter === "deleted") {
      return videoRepository.count({
        projectId: params.projectId,
        status: "DELETED",
      });
    }
    if (params.filter && params.filter !== "all") {
      const statusMap: Record<string, string> = {
        ready: "READY",
        processing: "PROCESSING",
        uploading: "UPLOADING",
        failed: "FAILED",
      };
      const status = statusMap[params.filter];
      if (status) {
        return videoRepository.count({
          projectId: params.projectId,
          status: status as VideoStatus,
        });
      }
    }
    return videoRepository.count({
      projectId: params.projectId,
      status: { not: "DELETED" },
    });
  },

  async getStatistics(videoId: string) {
    return videoRepository.getStatistics(videoId);
  },

  async getTimeline(videoId: string, take = 20) {
    return activityService.list({
      entity: "video",
      entityId: videoId,
      take,
    });
  },

  /** Generate signed URLs for a video's storage key. */
  async getSignedUrls(
    storageKey: string,
    thumbnailKey?: string | null
  ): Promise<{
    streamUrl: string;
    downloadUrl: string;
    thumbnailUrl: string | null;
  }> {
    const [streamUrl, downloadUrl, thumbnailUrl] = await Promise.all([
      storageService.getStreamingUrl(storageKey),
      storageService.getDownloadUrl(storageKey),
      thumbnailKey ? storageService.getSignedUrl(thumbnailKey) : Promise.resolve(null),
    ]);

    return { streamUrl, downloadUrl, thumbnailUrl };
  },

  /** Export all non-deleted videos as CSV rows. */
  async exportCsv(projectId?: string): Promise<string> {
    const videos = await videoRepository.findAllForExport(projectId);

    const headers = [
      "كود الفيديو",
      "العنوان",
      "الملف الأصلي",
      "المشروع",
      "كود المشروع",
      "الحالة",
      "المدة (ثانية)",
      "الدقة",
      "الحجم (بايت)",
      "النوع",
      "تاريخ الرفع",
    ];

    const escapeCsv = (value: string | null | undefined): string => {
      if (value == null) return "";
      const str = String(value);
      if (str.includes(",") || str.includes('"') || str.includes("\n")) {
        return `"${str.replace(/"/g, '""')}"`;
      }
      return str;
    };

    const statusLabels: Record<string, string> = {
      UPLOADING: "جاري الرفع",
      PROCESSING: "قالمعالجة",
      READY: "جاهز",
      FAILED: "فشل",
      DELETED: "محذوف",
    };

    const rows = videos.map((v) =>
      [
        v.videoCode,
        v.title,
        v.originalFileName,
        v.project.name,
        v.project.projectCode,
        statusLabels[v.status] ?? v.status,
        v.duration ? String(v.duration) : "",
        v.width && v.height ? `${v.width}x${v.height}` : "",
        String(v.fileSize),
        v.mimeType,
        v.createdAt.toISOString(),
      ]
        .map(escapeCsv)
        .join(",")
    );

    return "\uFEFF" + [headers.map(escapeCsv).join(","), ...rows].join("\n");
  },
};

import { prisma } from "@/lib/prisma";
import { deliveryRepository } from "@/repositories/delivery.repository";
import { activityService } from "@/services/activity.service";
import { storageService } from "@/lib/storage/storage.service";
import { generateToken } from "@/lib/utils";
import bcrypt from "bcryptjs";
import type { DeliveryStatus } from "@prisma/client";

/* ============================================
   Delivery Service
   Business logic layer — calls repositories only.
   ============================================ */

/** Format a sequential delivery code: DL-000001, DL-000002, etc. */
function formatDeliveryCode(sequence: number): string {
  return `DL-${String(sequence).padStart(6, "0")}`;
}

/** Generate the next unique delivery code using a transaction. */
async function generateUniqueDeliveryCode(): Promise<string> {
  return prisma.$transaction(async (tx) => {
    const latest = await tx.delivery.findFirst({
      orderBy: { deliveryCode: "desc" },
      select: { deliveryCode: true },
    });

    let sequence = 1;
    if (latest?.deliveryCode) {
      const match = latest.deliveryCode.match(/^DL-(\d+)$/);
      if (match) {
        sequence = parseInt(match[1]!, 10) + 1;
      }
    }

    return formatDeliveryCode(sequence);
  });
}

/** Generate a URL-safe slug from a title. */
function generateSlug(title: string): string {
  const base = title
    .trim()
    .toLowerCase()
    .replace(/[^\w\u0600-\u06FF\s-]/g, "")
    .replace(/\s+/g, "-")
    .slice(0, 50);
  const suffix = generateToken(8);
  return `${base}-${suffix}`;
}

/** Hash a password using bcrypt. */
async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}

/** Verify a password against a hash. */
async function verifyPassword(password: string, hash: string): Promise<boolean> {
  return bcrypt.compare(password, hash);
}

/** Check if delivery has expired. */
function isExpired(expiresAt: Date | null): boolean {
  if (!expiresAt) return false;
  return new Date() > expiresAt;
}

export const deliveryService = {
  async getById(id: string) {
    return deliveryRepository.findById(id);
  },

  async getBySlug(slug: string) {
    return deliveryRepository.findBySlug(slug);
  },

  async getByDeliveryCode(deliveryCode: string) {
    return deliveryRepository.findByDeliveryCode(deliveryCode);
  },

  async create(
    data: {
      projectId: string;
      title: string;
      expiresAt: Date;
      downloadEnabled: boolean;
      allowStreaming: boolean;
      allowComments: boolean;
      passwordProtected: boolean;
      password?: string;
      videoIds: string[];
    },
    options?: { actorId?: string }
  ) {
    const deliveryCode = await generateUniqueDeliveryCode();
    const slug = generateSlug(data.title);

    let passwordHash: string | null = null;
    if (data.passwordProtected && data.password) {
      passwordHash = await hashPassword(data.password);
    }

    const delivery = await deliveryRepository.create({
      deliveryCode,
      projectId: data.projectId,
      title: data.title.trim(),
      slug,
      status: "ACTIVE" as DeliveryStatus,
      expiresAt: data.expiresAt,
      downloadEnabled: data.downloadEnabled,
      allowStreaming: data.allowStreaming,
      allowComments: data.allowComments,
      passwordProtected: data.passwordProtected,
      passwordHash,
      viewCount: 0,
      downloadCount: 0,
    });

    // Set videos
    if (data.videoIds.length > 0) {
      await deliveryRepository.setVideos(delivery.id, data.videoIds);
    }

    // Activity log: Delivery Created
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "DELIVERY_CREATED",
        entity: "delivery",
        entityId: delivery.id,
        metadata: {
          deliveryCode: delivery.deliveryCode,
          title: delivery.title,
          projectId: delivery.projectId,
        },
      });
    }

    return delivery;
  },

  async update(
    id: string,
    data: {
      title: string;
      expiresAt: Date;
      downloadEnabled: boolean;
      allowStreaming: boolean;
      allowComments: boolean;
      passwordProtected: boolean;
      password?: string;
      videoIds: string[];
      status?: DeliveryStatus;
    },
    options?: { actorId?: string }
  ) {
    const updateData: Record<string, unknown> = {
      title: data.title.trim(),
      expiresAt: data.expiresAt,
      downloadEnabled: data.downloadEnabled,
      allowStreaming: data.allowStreaming,
      allowComments: data.allowComments,
      passwordProtected: data.passwordProtected,
    };

    if (data.status) {
      updateData.status = data.status;
    }

    // Handle password change
    if (data.passwordProtected && data.password) {
      updateData.passwordHash = await hashPassword(data.password);
    } else if (!data.passwordProtected) {
      updateData.passwordHash = null;
    }

    const delivery = await deliveryRepository.update(id, updateData as never);

    // Update videos
    await deliveryRepository.setVideos(id, data.videoIds);

    // Activity log: Delivery Updated
    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "DELIVERY_UPDATED",
        entity: "delivery",
        entityId: id,
        metadata: {
          deliveryCode: delivery.deliveryCode,
          title: delivery.title,
        },
      });
    }

    return delivery;
  },

  /** Soft delete — disable delivery. */
  async softDelete(id: string, options?: { actorId?: string }) {
    const delivery = await deliveryRepository.softDelete(id);

    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "DELIVERY_DISABLED",
        entity: "delivery",
        entityId: id,
        metadata: {
          deliveryCode: delivery.deliveryCode,
          title: delivery.title,
        },
      });
    }

    return delivery;
  },

  /** Restore a disabled delivery. */
  async restore(id: string, options?: { actorId?: string }) {
    const delivery = await deliveryRepository.restore(id);

    if (options?.actorId) {
      await activityService.log({
        userId: options.actorId,
        type: "DELIVERY_PUBLISHED",
        entity: "delivery",
        entityId: id,
        metadata: {
          deliveryCode: delivery.deliveryCode,
          title: delivery.title,
        },
      });
    }

    return delivery;
  },

  /** Soft delete alias. */
  async delete(id: string, options?: { actorId?: string }) {
    return this.softDelete(id, options);
  },

  async list(params: {
    projectId?: string;
    skip?: number;
    take?: number;
    search?: string;
    filter?: string;
    sort?: string;
  }) {
    return deliveryRepository.findMany(params);
  },

  async count(params: { projectId?: string; filter?: string }) {
    if (params.filter && params.filter !== "all") {
      const statusMap: Record<string, string> = {
        active: "ACTIVE",
        expired: "EXPIRED",
        disabled: "DISABLED",
      };
      const status = statusMap[params.filter];
      if (status) {
        return deliveryRepository.count({
          projectId: params.projectId,
          status: status as DeliveryStatus,
        });
      }
    }
    return deliveryRepository.count({
      projectId: params.projectId,
    });
  },

  async getStatistics(deliveryId: string) {
    return deliveryRepository.getStatistics(deliveryId);
  },

  async getTimeline(deliveryId: string, take = 20) {
    return activityService.list({
      entity: "delivery",
      entityId: deliveryId,
      take,
    });
  },

  /** Check delivery access status for public portal. */
  checkAccess(delivery: {
    status: string;
    expiresAt: Date | null;
  }): "active" | "expired" | "disabled" {
    if (delivery.status === "DISABLED") return "disabled";
    if (isExpired(delivery.expiresAt)) return "expired";
    return "active";
  },

  /** Verify password for a delivery. */
  async verifyPassword(slug: string, password: string): Promise<boolean> {
    const delivery = await deliveryRepository.findBySlug(slug);
    if (!delivery || !delivery.passwordProtected || !delivery.passwordHash) {
      return false;
    }
    return verifyPassword(password, delivery.passwordHash);
  },

  /** Increment view count (public). */
  async trackView(id: string) {
    return deliveryRepository.incrementViewCount(id);
  },

  /** Increment download count and get signed URL (public). */
  async trackDownload(id: string, storageKey: string): Promise<string> {
    await deliveryRepository.incrementDownloadCount(id);
    return storageService.getDownloadUrl(storageKey);
  },

  /** Get signed streaming URL for a video (public). */
  async getStreamUrl(storageKey: string): Promise<string> {
    return storageService.getStreamingUrl(storageKey);
  },

  /** Get signed download URL (public). */
  async getDownloadUrl(storageKey: string): Promise<string> {
    return storageService.getDownloadUrl(storageKey);
  },
};

