        fileSize: parsed.data.fileSize,
        duration: parsed.data.duration,
        width: parsed.data.width,
        height: parsed.data.height,
      },
      { actorId: user.id }
    );

    revalidatePath(ROUTES.DASHBOARD_UPLOADS);
    return { success: true, videoId: video.id };
